import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

function ImageAnalyzer() {
  const [selectedImage, setSelectedImage] = useState(null);
  const [preview, setPreview] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [results, setResults] = useState(null);
  const [analysis, setAnalysis] = useState('');
  const navigate = useNavigate();

  const handleImageSelect = (e) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedImage(file);
      const reader = new FileReader();
      reader.onload = (event) => {
        setPreview(event.target?.result);
      };
      reader.readAsDataURL(file);
      setError('');
      setResults(null);
    }
  };

  const handleAnalyze = async () => {
    if (!selectedImage) {
      setError('Please select an image first');
      return;
    }

    setLoading(true);
    setError('');
    setResults(null);

    try {
      // Convert image to base64
      const reader = new FileReader();
      reader.onload = async () => {
        const base64Image = reader.result.split(',')[1];

        // Send to backend for AI analysis
        const response = await axios.post('/api/ai/analyze-image', {
          image: base64Image,
          imageType: selectedImage.type
        });

        setAnalysis(response.data.analysis);

        // Get products from database
        const productsResponse = await axios.get('/api/products');
        const allProducts = productsResponse.data;

        // Filter products based on analysis keywords
        const keywords = response.data.keywords || [];
        const matchingProducts = allProducts.filter(product => {
          const productName = product.name.toLowerCase();
          const productCategory = (product.category || '').toLowerCase();

          return keywords.some(keyword => {
            const kw = keyword.toLowerCase();
            return productName.includes(kw) || productCategory.includes(kw);
          });
        });

        setResults({
          analysis: response.data.analysis,
          keywords: keywords,
          products: matchingProducts.slice(0, 9) // Show top 9 products
        });
      };
      reader.readAsArrayBuffer(selectedImage);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to analyze image. Make sure the backend API is set up.');
      console.error('Error:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleClear = () => {
    setSelectedImage(null);
    setPreview(null);
    setResults(null);
    setAnalysis('');
    setError('');
  };

  const inputStyle = {
    width: '100%',
    padding: '12px 10px',
    border: '1px solid #f0f0f0',
    fontSize: '13px',
    fontFamily: 'Helvetica, Arial, sans-serif',
    color: '#000',
    boxSizing: 'border-box'
  };

  const labelStyle = {
    display: 'block',
    fontSize: '11px',
    fontWeight: '400',
    letterSpacing: '0.5px',
    textTransform: 'uppercase',
    color: '#999',
    marginBottom: '8px'
  };

  return (
    <div style={{
      padding: '60px 50px',
      backgroundColor: '#fff',
      fontFamily: 'Helvetica, Arial, sans-serif'
    }}>
      <h1 style={{
        fontSize: '28px',
        fontWeight: '300',
        letterSpacing: '1px',
        color: '#000',
        margin: '0 0 20px 0',
        textTransform: 'uppercase'
      }}>
        FIND SIMILAR PRODUCTS
      </h1>

      <p style={{
        fontSize: '13px',
        color: '#666',
        margin: '0 0 40px 0',
        lineHeight: '1.6'
      }}>
        Upload an image of clothing or style you like, and our AI will find similar products in our catalog.
      </p>

      {error && (
        <div style={{
          padding: '12px',
          backgroundColor: '#ffebee',
          color: '#d32f2f',
          fontSize: '12px',
          marginBottom: '30px',
          letterSpacing: '0.5px',
          borderRadius: '4px'
        }}>
          {error}
        </div>
      )}

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '40px', marginBottom: '40px' }}>
        {/* Upload Section */}
        <div>
          <h3 style={{
            fontSize: '13px',
            fontWeight: '400',
            letterSpacing: '0.5px',
            color: '#000',
            margin: '0 0 20px 0',
            textTransform: 'uppercase'
          }}>
            UPLOAD IMAGE
          </h3>

          <div style={{
            border: '2px dashed #f0f0f0',
            borderRadius: '4px',
            padding: '40px',
            textAlign: 'center',
            cursor: 'pointer',
            transition: 'all 0.3s',
            backgroundColor: preview ? '#f9f9f9' : '#fff'
          }}>
            <input
              type="file"
              accept="image/*"
              onChange={handleImageSelect}
              style={{ display: 'none' }}
              id="image-input"
            />

            <label htmlFor="image-input" style={{ cursor: 'pointer', display: 'block' }}>
              {preview ? (
                <div>
                  <img
                    src={preview}
                    alt="Preview"
                    style={{
                      maxWidth: '100%',
                      maxHeight: '300px',
                      marginBottom: '15px',
                      borderRadius: '4px'
                    }}
                  />
                  <p style={{ fontSize: '12px', color: '#999', margin: '10px 0' }}>
                    Click to change image
                  </p>
                </div>
              ) : (
                <div>
                  <div style={{
                    fontSize: '32px',
                    marginBottom: '10px'
                  }}>
                    📸
                  </div>
                  <p style={{
                    fontSize: '13px',
                    color: '#000',
                    margin: '0 0 5px 0'
                  }}>
                    Click to upload or drag and drop
                  </p>
                  <p style={{
                    fontSize: '11px',
                    color: '#999',
                    margin: '0'
                  }}>
                    PNG, JPG, GIF up to 10MB
                  </p>
                </div>
              )}
            </label>
          </div>

          {selectedImage && (
            <div style={{ marginTop: '20px', display: 'flex', gap: '10px' }}>
              <button
                onClick={handleAnalyze}
                disabled={loading}
                style={{
                  flex: 1,
                  padding: '12px',
                  backgroundColor: loading ? '#ccc' : '#000',
                  color: '#fff',
                  border: 'none',
                  fontSize: '12px',
                  fontFamily: 'Helvetica, Arial, sans-serif',
                  fontWeight: '400',
                  letterSpacing: '1px',
                  textTransform: 'uppercase',
                  cursor: loading ? 'not-allowed' : 'pointer',
                  transition: 'opacity 0.3s',
                  borderRadius: '2px'
                }}
                onMouseEnter={(e) => !loading && (e.target.style.opacity = '0.8')}
                onMouseLeave={(e) => !loading && (e.target.style.opacity = '1')}
              >
                {loading ? 'ANALYZING...' : 'ANALYZE IMAGE'}
              </button>

              <button
                onClick={handleClear}
                style={{
                  flex: 1,
                  padding: '12px',
                  backgroundColor: '#fff',
                  color: '#000',
                  border: '1px solid #f0f0f0',
                  fontSize: '12px',
                  fontFamily: 'Helvetica, Arial, sans-serif',
                  fontWeight: '400',
                  letterSpacing: '1px',
                  textTransform: 'uppercase',
                  cursor: 'pointer',
                  transition: 'all 0.3s',
                  borderRadius: '2px'
                }}
                onMouseEnter={(e) => {
                  e.target.style.borderColor = '#000';
                  e.target.style.color = '#000';
                }}
                onMouseLeave={(e) => {
                  e.target.style.borderColor = '#f0f0f0';
                  e.target.style.color = '#000';
                }}
              >
                CLEAR
              </button>
            </div>
          )}
        </div>

        {/* Analysis Section */}
        <div>
          <h3 style={{
            fontSize: '13px',
            fontWeight: '400',
            letterSpacing: '0.5px',
            color: '#000',
            margin: '0 0 20px 0',
            textTransform: 'uppercase'
          }}>
            AI ANALYSIS
          </h3>

          <div style={{
            backgroundColor: '#f9f9f9',
            padding: '20px',
            borderRadius: '4px',
            minHeight: '200px',
            border: '1px solid #f0f0f0'
          }}>
            {loading ? (
              <div style={{ textAlign: 'center', padding: '40px 20px' }}>
                <div style={{ fontSize: '24px', marginBottom: '10px' }}>🤖</div>
                <p style={{ fontSize: '13px', color: '#666' }}>
                  Analyzing image with AI...
                </p>
              </div>
            ) : analysis ? (
              <div>
                <p style={{
                  fontSize: '12px',
                  color: '#333',
                  lineHeight: '1.6',
                  margin: '0 0 15px 0'
                }}>
                  {analysis}
                </p>

                {results?.keywords && results.keywords.length > 0 && (
                  <div>
                    <p style={{
                      fontSize: '11px',
                      fontWeight: '500',
                      color: '#999',
                      textTransform: 'uppercase',
                      margin: '0 0 10px 0'
                    }}>
                      Key Style Elements:
                    </p>
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                      {results.keywords.map((keyword, idx) => (
                        <span
                          key={idx}
                          style={{
                            backgroundColor: '#000',
                            color: '#fff',
                            padding: '4px 10px',
                            fontSize: '10px',
                            borderRadius: '2px',
                            textTransform: 'capitalize'
                          }}
                        >
                          {keyword}
                        </span>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            ) : (
              <p style={{ fontSize: '12px', color: '#999', textAlign: 'center' }}>
                Upload an image and click "Analyze Image" to see AI analysis
              </p>
            )}
          </div>
        </div>
      </div>

      {/* Results Section */}
      {results && results.products.length > 0 && (
        <div>
          <h3 style={{
            fontSize: '13px',
            fontWeight: '400',
            letterSpacing: '0.5px',
            color: '#000',
            margin: '0 0 30px 0',
            textTransform: 'uppercase'
          }}>
            MATCHING PRODUCTS ({results.products.length})
          </h3>

          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(3, 1fr)',
            gap: '0'
          }}>
            {results.products.map(product => (
              <div
                key={product._id}
                onClick={() => navigate(`/product/${product._id}`)}
                style={{
                  borderRight: '1px solid #f0f0f0',
                  borderBottom: '1px solid #f0f0f0',
                  cursor: 'pointer',
                  transition: 'opacity 0.3s'
                }}
                onMouseEnter={(e) => e.currentTarget.style.opacity = '0.9'}
                onMouseLeave={(e) => e.currentTarget.style.opacity = '1'}
              >
                <div style={{
                  aspectRatio: '1000 / 1400',
                  backgroundColor: '#f9f9f9',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  overflow: 'hidden'
                }}>
                  <img
                    src={product.media?.featured || `/products/${product._id}.jpg`}
                    alt={product.name}
                    style={{
                      width: '100%',
                      height: '100%',
                      objectFit: 'cover'
                    }}
                  />
                </div>

                <div style={{
                  padding: '20px',
                  borderRight: '1px solid #f0f0f0',
                  borderBottom: '1px solid #f0f0f0'
                }}>
                  <h4 style={{
                    fontSize: '13px',
                    fontFamily: 'Helvetica, Arial, sans-serif',
                    fontWeight: '400',
                    letterSpacing: '0.5px',
                    color: '#000',
                    margin: '0 0 10px 0',
                    textTransform: 'uppercase'
                  }}>
                    {product.name}
                  </h4>
                  <p style={{
                    fontSize: '13px',
                    fontFamily: 'Helvetica, Arial, sans-serif',
                    fontWeight: '500',
                    color: '#000',
                    margin: '0',
                    letterSpacing: '0.5px'
                  }}>
                    ${product.price}
                  </p>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {results && results.products.length === 0 && (
        <div style={{
          padding: '40px',
          textAlign: 'center',
          backgroundColor: '#f9f9f9',
          borderRadius: '4px'
        }}>
          <p style={{ fontSize: '13px', color: '#999' }}>
            No matching products found. Try uploading a different image.
          </p>
        </div>
      )}
    </div>
  );
}

export default ImageAnalyzer;
